{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from single-recipient to multi-recipient shipments. This is a fundamental change to the Shipment aggregate — one of the most central entities in any logistics system. It affects data modeling, external integrations, operational workflows, and the meaning of 'delivery' itself. With 2M production shipments and external partner API contracts, this is not a simple schema change — it is a redefinition of what a Shipment means.",
    "bounded_context": "Shipment / Delivery Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A logistical unit representing the movement of goods from origin to one or more destinations. The aggregate root that owns Recipients." },
      { "term": "Recipient", "definition": "A party designated to receive a delivery, identified by name, address, phone number, and delivery preferences. A Shipment has 1..N Recipients." },
      { "term": "Delivery Preferences", "definition": "Recipient-level instructions governing how and when delivery should occur (e.g., time windows, signature requirements, safe-place instructions, authority to leave)." },
      { "term": "Delivery Event", "definition": "A domain event recording the outcome of a delivery attempt for a specific Recipient within a Shipment." },
      { "term": "Shipment Status", "definition": "The aggregate lifecycle state of a Shipment. In a multi-recipient model, this becomes a composite derived from the statuses of individual Recipient deliveries." },
      { "term": "Partner Integration", "definition": "External API contract through which shipment data is exchanged with third-party logistics partners in a defined format." },
      { "term": "Split Delivery", "definition": "The operational scenario where a single Shipment results in multiple physical delivery stops, one per Recipient." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient. Zero-recipient Shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A Shipment without a Recipient has no destination and cannot exist in any physically meaningful state. This is a structural integrity constraint — the system is corrupt if violated.",
      "testable_assertion": "Creating or updating a Shipment with an empty Recipients collection must be rejected at the domain level."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a unique delivery address. Duplicate addresses within the same Shipment are disallowed.",
      "invariant": true,
      "invariant_justification": "Two Recipients at the same address on the same Shipment would create ambiguous routing and duplicate delivery attempts. If the business truly needs this, they should be separate Shipments or the Recipients should be merged with distinct contact names.",
      "testable_assertion": "Adding a Recipient whose address matches an existing Recipient on the same Shipment must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient must have a name, address, and phone number. Delivery preferences are optional and default to standard delivery if not specified.",
      "invariant": true,
      "invariant_justification": "Name, address, and phone are the minimum data required to execute a physical delivery and contact the recipient. Without these, the delivery cannot be attempted.",
      "testable_assertion": "A Recipient missing name, address, or phone number must fail validation before being added to a Shipment."
    },
    {
      "id": "BR-4",
      "rule": "Shipment-level status must be derived from the individual Recipient delivery statuses. A Shipment is 'Delivered' only when ALL Recipients have received their delivery.",
      "invariant": true,
      "invariant_justification": "If Shipment status does not accurately reflect the state of all its constituent deliveries, operational dashboards, SLA tracking, and billing will be incorrect. This is data consistency.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are 'Delivered' and 1 is 'In Transit' must report Shipment status as 'Partially Delivered' or equivalent, never 'Delivered'."
    },
    {
      "id": "BR-5",
      "rule": "Delivery preferences are scoped to the individual Recipient, not to the Shipment. Each Recipient's preferences are independent.",
      "invariant": false,
      "invariant_justification": "This is a business policy reflecting the product team's stated requirement. A future policy change could allow Shipment-level default preferences that Recipients inherit.",
      "testable_assertion": "Setting delivery preferences on Recipient A must not affect Recipient B's preferences within the same Shipment."
    },
    {
      "id": "BR-6",
      "rule": "Existing single-recipient Shipments in production must remain valid and queryable without data loss after the model evolution.",
      "invariant": true,
      "invariant_justification": "2 million production records represent real business transactions. Data corruption or loss would break audit trails, billing, dispute resolution, and partner trust. This is data integrity.",
      "testable_assertion": "All 2M existing Shipments must be queryable after migration, each returning exactly one Recipient with all original fields preserved."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in a backward-compatible format until partners have migrated to the new contract.",
      "invariant": false,
      "invariant_justification": "This is a business policy driven by partner contracts and migration timelines, not a physical or data integrity constraint. The constraint can be relaxed once partners upgrade.",
      "testable_assertion": "Partner API payloads for single-recipient Shipments must be structurally identical to the pre-migration format. Multi-recipient Shipments sent to non-upgraded partners must either be rejected or serialized with a designated primary Recipient."
    },
    {
      "id": "BR-8",
      "rule": "A Shipment with multiple Recipients must define a primary Recipient for backward-compatibility contexts (billing address, partner API fallback, return-to-sender).",
      "invariant": false,
      "invariant_justification": "This is a policy to manage the transition period and legacy integrations. It could be deprecated once all consumers understand multi-recipient semantics.",
      "testable_assertion": "A multi-recipient Shipment must have exactly one Recipient flagged as primary. Creating a multi-recipient Shipment without a primary must fail validation."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The sender specifies 3 Recipients with different addresses and delivery preferences",
      "then": "The Shipment is created with all 3 Recipients, each preserving their individual delivery preferences, and Shipment status is 'Created'"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "The Shipment is queried via the API",
      "then": "It returns a Recipients array with exactly one entry containing the original name, address, phone, and default delivery preferences"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where 2 of 3 Recipients have been delivered",
      "when": "The Shipment status is queried",
      "then": "The status is 'Partially Delivered' and each Recipient's individual delivery status is independently queryable"
    },
    {
      "id": "AC-4",
      "given": "A partner API integration that has NOT been upgraded",
      "when": "A single-recipient Shipment is sent to that partner",
      "then": "The payload format is identical to the pre-migration schema — no breaking changes"
    },
    {
      "id": "AC-5",
      "given": "A partner API integration that has NOT been upgraded",
      "when": "A multi-recipient Shipment is sent to that partner",
      "then": "The system either sends only the primary Recipient in the legacy format OR rejects the send with a clear error indicating the partner must upgrade"
    },
    {
      "id": "AC-6",
      "given": "A Shipment is being created with zero Recipients",
      "when": "The creation request is submitted",
      "then": "The request is rejected with a validation error: 'Shipment must have at least one Recipient'"
    },
    {
      "id": "AC-7",
      "given": "A Shipment with 2 Recipients at the same address",
      "when": "The creation request is submitted",
      "then": "The request is rejected with a validation error: 'Duplicate delivery address within the same Shipment'"
    },
    {
      "id": "AC-8",
      "given": "The data migration has been executed on the production database",
      "when": "A count query is run on the new Recipients table/collection",
      "then": "Exactly 2 million Recipient records exist, one for each pre-existing Shipment, with all original data intact and each flagged as primary"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where one Recipient's delivery fails permanently (address invalid, refused) while others succeed",
      "expected_behavior": "The Shipment enters a 'Partially Delivered' terminal state. The failed Recipient has a clear failure reason. Return-to-sender or re-routing logic applies only to the failed Recipient's portion. The Shipment is never marked 'Delivered'."
    },
    {
      "scenario": "A Recipient is removed from a Shipment after it has already been dispatched but before delivery",
      "expected_behavior": "Domain must decide: is Recipient removal allowed post-dispatch? If the physical goods are on a single vehicle, removal may not be operationally possible. This needs a clear business rule — likely disallow removal after dispatch, only allow preference changes or redirect."
    },
    {
      "scenario": "Two Recipients on the same Shipment have conflicting delivery preferences (e.g., one requires morning delivery, another requires evening, and a single driver services both)",
      "expected_behavior": "Preferences are per-Recipient and may result in separate delivery runs. The routing/dispatch system must handle this as potentially multiple stops on different schedules. No silent preference override."
    },
    {
      "scenario": "External partner sends a webhook update for a Shipment using the old single-recipient format",
      "expected_behavior": "The system must match the update to the correct Recipient (likely the primary). If the update is ambiguous (e.g., address-based matching), it should fail gracefully rather than apply to the wrong Recipient."
    },
    {
      "scenario": "Billing and pricing for a multi-recipient Shipment vs. multiple single-recipient Shipments",
      "expected_behavior": "The pricing model must be explicitly defined: is a 3-recipient Shipment priced as 1 shipment or 3? This directly affects revenue. Until defined, this is a blocking ambiguity."
    },
    {
      "scenario": "A Shipment with 100+ Recipients (bulk/batch scenario)",
      "expected_behavior": "Must define a maximum Recipient count per Shipment to prevent abuse and operational infeasibility. Without a cap, a single Shipment could overwhelm routing, tracking UI, and partner integrations."
    },
    {
      "scenario": "Migration rollback needed after partial execution on 2M records",
      "expected_behavior": "The migration must be reversible. If the new schema is deployed and issues arise, the system must be able to fall back to single-recipient behavior without data loss."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient Shipments directly affect pricing model — if a 3-recipient shipment is priced as 1, revenue drops ~66% for those orders vs. 3 separate shipments. Conversely, if priced higher, it creates a new premium product line. Migration itself carries cost: engineering time, testing, partner coordination, and potential downtime during data migration of 2M records.",
    "operational": "HIGH. Routing and dispatch systems must now handle multiple stops per Shipment. Driver apps need multi-stop UX. Tracking dashboards need per-Recipient status views. Customer support must handle 'my package was delivered but my co-recipient's wasn't' scenarios. SLA calculations become composite. Sorting facilities may need new scanning workflows.",
    "user": "MEDIUM-HIGH. Senders gain flexibility (one order, multiple destinations — common for gifts, corporate distributions). Recipients get personalized delivery preferences. However, tracking UX becomes more complex — 'Where is my package?' now depends on which Recipient you are. Notification systems must be per-Recipient.",
    "risk": "HIGH. Data migration of 2M records carries integrity risk. External partner API backward compatibility is fragile — silent failures could cause lost deliveries. The new composite Shipment status introduces state machine complexity that is historically error-prone. If the Recipient-removal-post-dispatch rule is not defined, operational chaos follows.",
    "stakeholders_affected": [
      { "group": "Senders (Customers)", "impact": "New capability to send to multiple recipients in one shipment. UX must clearly communicate per-recipient tracking and delivery status." },
      { "group": "Recipients", "impact": "Gain individual delivery preferences. Must receive independent tracking links and notifications." },
      { "group": "Drivers / Couriers", "impact": "Multi-stop routes per shipment. Driver app must display per-recipient instructions. Proof-of-delivery becomes per-recipient." },
      { "group": "External Partners", "impact": "API contract change. Partners on legacy format risk receiving incomplete data or breaking. Requires coordinated migration timeline." },
      { "group": "Customer Support", "impact": "Significantly more complex inquiry resolution. Must be able to query and act on individual Recipient statuses within a Shipment." },
      { "group": "Finance / Billing", "impact": "Pricing model must be redefined. Invoice line items change. Revenue recognition may be affected if delivery is partial." },
      { "group": "Operations / Dispatch", "impact": "Route optimization algorithms must account for multi-stop shipments. Sorting and scanning workflows change." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is clear about the structural model change (1-to-many Recipients with preferences) and the migration context (2M records, partner APIs). However, several critical business decisions are unspecified: pricing model for multi-recipient shipments, maximum recipient count, Recipient mutability post-dispatch, composite status state machine definition, partner migration timeline and strategy, and the exact semantics of 'delivery preferences.' These gaps mean acceptance criteria are based on reasonable domain assumptions but cannot be considered authoritative without product clarification.",
    "high_confidence_areas": [
      "The 1..N cardinality change and its structural implications",
      "Data migration requirement for 2M existing records",
      "Partner API backward compatibility necessity",
      "Per-Recipient delivery preference isolation",
      "Need for composite Shipment status"
    ],
    "low_confidence_areas": [
      "Pricing model for multi-recipient shipments (not specified)",
      "Maximum Recipient count per Shipment (not specified)",
      "Whether Recipients can be added/removed after Shipment dispatch",
      "Exact definition and schema of 'delivery preferences'",
      "Partner migration strategy and timeline",
      "Whether duplicate-address validation is truly desired (could be two different people at same address)"
    ],
    "assumptions": [
      "Delivery preferences include time windows, signature requirements, and safe-place instructions — but exact schema is assumed",
      "A primary Recipient concept is needed for backward compatibility — not stated in spec but domain-necessary",
      "Duplicate addresses within a Shipment are invalid — this is a domain judgment that the product team may override",
      "Shipment status must become composite — not stated but logically required by multi-recipient model"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The pricing model for multi-recipient Shipments is undefined. Is a 3-recipient Shipment priced as one shipment, three shipments, or a new tiered model? This has direct revenue impact and must be resolved before implementation.",
      "affected_stakeholders": ["Finance / Billing", "Senders (Customers)", "Product"],
      "options": [
        "Price as single shipment with surcharge per additional recipient",
        "Price as N separate shipments bundled under one tracking umbrella",
        "New pricing tier: multi-recipient shipment as a distinct product"
      ],
      "recommendation": "Define as a distinct product with per-recipient surcharge. This preserves revenue while offering sender value."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'delivery preferences' but does not define what preferences are available. Time windows? Signature required? Authority to leave? Contactless? The domain model and UI cannot be built without this definition.",
      "affected_stakeholders": ["Recipients", "Drivers / Couriers", "Product"],
      "options": [
        "Define a minimal set: time window, signature required, safe place instructions",
        "Define an extensible preferences schema that can grow over time",
        "Copy preferences model from an existing competitor or industry standard"
      ],
      "recommendation": "Start with a minimal, extensible set: delivery time window, signature requirement, safe-place instructions, and a free-text 'special instructions' field."
    },
    {
      "type": "ambiguity",
      "description": "No maximum Recipient count per Shipment is specified. Without a cap, the system is vulnerable to abuse and operational infeasibility (imagine a Shipment with 10,000 Recipients).",
      "affected_stakeholders": ["Operations / Dispatch", "Drivers / Couriers", "Engineering"],
      "options": [
        "Hard cap at 5 recipients (covers 99% of use cases: gifts, small business)",
        "Hard cap at 20 recipients (covers corporate distribution)",
        "Soft cap with approval workflow for bulk"
      ],
      "recommendation": "Hard cap at 10 recipients initially with a business justification workflow for higher counts. This covers gift and small corporate use cases without operational risk."
    },
    {
      "type": "missing_context",
      "description": "The partner API migration strategy is unspecified. How many partners exist? What are their contract terms? Can we version the API or must we maintain backward compatibility indefinitely? The answer drives whether BR-7 and BR-8 are temporary or permanent.",
      "affected_stakeholders": ["External Partners", "Engineering", "Business Development"],
      "options": [
        "Maintain legacy format indefinitely with adapter layer",
        "Set a deprecation timeline (e.g., 6 months) and require partner migration",
        "Version the API (v1 = legacy, v2 = multi-recipient) and let partners migrate on their own schedule"
      ],
      "recommendation": "API versioning (v1/v2) with a 12-month deprecation window for v1. This respects partner contracts while creating a clear migration path."
    },
    {
      "type": "ambiguity",
      "description": "Can Recipients be added to or removed from a Shipment after it has been dispatched? This is operationally critical — physical goods are already in transit.",
      "affected_stakeholders": ["Operations / Dispatch", "Senders (Customers)", "Drivers / Couriers"],
      "options": [
        "Lock Recipients at dispatch — no additions or removals",
        "Allow additions but not removals (redirect additional goods)",
        "Allow modifications with operational approval workflow"
      ],
      "recommendation": "Lock Recipients at dispatch. Post-dispatch changes should be handled through a separate 'redirect' or 'return' workflow, not by mutating the Shipment aggregate."
    }
  ],

  "rejection_reasons": []
}

